import numpy as np

def homo_lumo_gap(orbital_energies, n_occ):
    """Calculate HOMO-LUMO gap in eV."""
    homo = orbital_energies[n_occ - 1]
    lumo = orbital_energies[n_occ]
    gap_hartree = lumo - homo
    return gap_hartree * 27.211

def classify_by_gap(gap_ev):
    """Classify molecule based on gap."""
    if gap_ev > 6:
        return {
            'type': 'Insulator',
            'stability': 'High',
            'color': 'Colorless',
            'reactivity': 'Low'
        }
    elif gap_ev > 2:
        return {
            'type': 'Semiconductor',
            'stability': 'Medium',
            'color': 'Possibly colored',
            'reactivity': 'Medium'
        }
    else:
        return {
            'type': 'Conductor',
            'stability': 'Low',
            'color': 'Colored',
            'reactivity': 'High'
        }

# Test
molecules = {
    'Benzene': (np.array([-10.0, -0.5, -0.34, 0.05, 0.2]), 3),
    'Ethene': (np.array([-10.0, -0.37, 0.12, 0.3]), 2),
    'Polyene': (np.array([-5.0, -0.15, 0.02, 0.1]), 2),
}

for name, (orbs, n_occ) in molecules.items():
    gap = homo_lumo_gap(orbs, n_occ)
    props = classify_by_gap(gap)
    print(f"{name}: Gap = {gap:.2f} eV")
    print(f"  Properties: {props}")

import numpy as np

def chemical_hardness(homo_ev, lumo_ev):
    """Calculate chemical hardness η = (LUMO - HOMO)/2."""
    return (lumo_ev - homo_ev) / 2

def chemical_softness(hardness):
    """Calculate chemical softness S = 1/η."""
    if hardness == 0:
        return float('inf')
    return 1.0 / hardness

def analyze_reactivity(homo_ev, lumo_ev):
    """Analyze reactivity based on frontier orbitals."""
    hardness = chemical_hardness(homo_ev, lumo_ev)
    softness = chemical_softness(hardness)
    electronegativity = -(homo_ev + lumo_ev) / 2

    # Classify
    if hardness > 5:
        character = 'Hard'
    elif hardness > 3:
        character = 'Borderline'
    else:
        character = 'Soft'

    return {
        'hardness': hardness,
        'softness': softness,
        'electronegativity': electronegativity,
        'character': character
    }

# Test
molecules = [
    ('Benzene', -9.2, 0.0),
    ('Ethene', -10.5, 0.8),
    ('Na atom', -5.1, -0.6),
    ('Cl atom', -13.0, -3.6),
]

for name, homo, lumo in molecules:
    analysis = analyze_reactivity(homo, lumo)
    print(f"{name}: η={analysis['hardness']:.2f}, χ={analysis['electronegativity']:.2f}, {analysis['character']}")
